```class Solution {
    public int nthUglyNumber(int n) {
        int[] factors = new int[3];
        factors[0] = 2;
        factors[1] = 3;
        factors[2] = 5;
        int result = 1;
        for (int i = 1; i <= n; i++) {
            int sum = 1;
            for (int j = 0; j < 3; j++) {
                sum *= factors[j];
            }
            result = Math.min(result, sum);
        }
        return result;
    }
}
```

